class Solution:
    def countOfPeaks(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        from collections import defaultdict

        n = len(nums)
        # Precompute peaks: a boolean array where peaks[i] is True if nums[i] is a peak
        peaks = [False] * n
        for i in range(1, n - 1):
            if nums[i] > nums[i - 1] and nums[i] > nums[i + 1]:
                peaks[i] = True

        # Segment tree to store the count of peaks in ranges
        class SegmentTree:
            def __init__(self, data):
                self.n = len(data)
                self.tree = [0] * (2 * self.n)
                for i in range(self.n):
                    self.tree[self.n + i] = data[i]
                for i in range(self.n - 1, 0, -1):
                    self.tree[i] = self.tree[2 * i] + self.tree[2 * i + 1]

            def update(self, pos, value):
                pos += self.n
                self.tree[pos] = value
                pos //= 2
                while pos >= 1:
                    self.tree[pos] = self.tree[2 * pos] + self.tree[2 * pos + 1]
                    pos //= 2

            def query(self, l, r):
                res = 0
                l += self.n
                r += self.n
                while l <= r:
                    if l % 2 == 1:
                        res += self.tree[l]
                        l += 1
                    if r % 2 == 0:
                        res += self.tree[r]
                        r -= 1
                    l //= 2
                    r //= 2
                return res

        # Initialize the segment tree with the peaks array
        seg_tree = SegmentTree(peaks)

        result = []

        for query in queries:
            if query[0] == 1:
                l, r = query[1], query[2]
                # Query the number of peaks in [l, r]
                # Since the first and last elements cannot be peaks, we adjust the range
                count = seg_tree.query(max(l + 1, 0), min(r - 1, n - 1))
                result.append(count)
            else:
                idx, val = query[1], query[2]
                # Update nums[idx] to val
                nums[idx] = val
                # Update the peaks array
                # Check if idx - 1 is a peak
                if idx - 1 >= 1 and idx - 1 < n - 1:
                    if nums[idx - 1] > nums[idx - 2] and nums[idx - 1] > nums[idx]:
                        peaks[idx - 1] = True
                    else:
                        peaks[idx - 1] = False
                # Check if idx is a peak
                if idx >= 1 and idx < n - 1:
                    if nums[idx] > nums[idx - 1] and nums[idx] > nums[idx + 1]:
                        peaks[idx] = True
                    else:
                        peaks[idx] = False
                # Check if idx + 1 is a peak
                if idx + 1 < n - 1 and idx + 1 >= 1:
                    if nums[idx + 1] > nums[idx] and nums[idx + 1] > nums[idx + 2]:
                        peaks[idx + 1] = True
                    else:
                        peaks[idx + 1] = False
                # Update the segment tree
                seg_tree.update(idx - 1, peaks[idx - 1])
                seg_tree.update(idx, peaks[idx])
                seg_tree.update(idx + 1, peaks[idx + 1])

        return result
